import 'dart:convert'; import 'dart:typed_data'; import 'package:uuid/uuid.dart'; import '../models/normalized_anpr_event.dart';
class ManualProtobufAnprParser{static NormalizedAnprEvent parse(List<int> bytes){final r=_R(Uint8List.fromList(bytes)); final f=<String,dynamic>{}; while(!r.end){final key=r.varint(); final num=key>>3; final wt=key&7; final name=_names[num]??'field_$num'; dynamic val; switch(wt){case 0: val=r.varint(); break; case 1: val=r.f64(); break; case 2: val=utf8.decode(r.len(),allowMalformed:true); break; case 5: val=r.f32(); break; default: throw FormatException('Unsupported protobuf wire type: $wt');} f[name]=val;} return NormalizedAnprEvent.fromMappedFields(sourceFormat:'PROTOBUF',fields:f,rawPayload:'Binary protobuf payload: ${bytes.length} bytes',fallbackId:const Uuid().v4());}
static const _names=<int,String>{1:'id',2:'plate_number',3:'plate_number_arabic',4:'country',5:'emirate',6:'vehicle_type',7:'vehicle_color',8:'make',9:'model',10:'camera_id',11:'camera_name',12:'location_name',13:'lane',14:'direction',15:'confidence',16:'timestamp',17:'vehicle_image',18:'plate_image'};}
class _R{final Uint8List d; int o=0; _R(this.d); bool get end=>o>=d.length; int varint(){var res=0,sh=0; while(true){if(o>=d.length)throw const FormatException('Unexpected EOF'); final b=d[o++]; res|=(b&0x7F)<<sh; if((b&0x80)==0)return res; sh+=7; if(sh>63)throw const FormatException('Malformed varint');}} Uint8List len(){final l=varint(); if(o+l>d.length)throw const FormatException('Unexpected EOF'); final out=d.sublist(o,o+l); o+=l; return out;} double f64(){if(o+8>d.length)throw const FormatException('Unexpected EOF'); final bd=ByteData.sublistView(d,o,o+8); o+=8; return bd.getFloat64(0,Endian.little);} int f32(){if(o+4>d.length)throw const FormatException('Unexpected EOF'); final bd=ByteData.sublistView(d,o,o+4); o+=4; return bd.getUint32(0,Endian.little);}}
